command.text:

var f = this, e = 'ky', errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">Từ ngày</span> phải nhỏ hơn hoặc bằng <span class="Highlight">Đến ngày</span>.' : '<span class="Highlight">Date from</span> must be less than or equal to <span class="Highlight">date to</span>.');
var p = f.getItemValue(e);
if (p < 1 || p > f._periodCount) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), f.getItem(e).field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', f.get_id(), e));
}

if (f._checked && (f.getItemValue('ngay_tu') > f.getItemValue('ngay_den'))) {
  $func.hideWait(f.get_id());
  f._checked = false;
  $message.show(errorMessage, String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), 'ngay_tu'));
}

script.text:

function active$SalaryComputingPeriod(f) {
  f.add_onResponseComplete(on$SalaryComputingPeriod$ResponseComplete);
  setDefault$SalaryComputingPeriod$Value(f);
}
function scatter$SalaryComputingPeriod(f) {setDefault$SalaryComputingPeriod$Value(f);}
function setDefault$SalaryComputingPeriod$Value(f) {
	var d = new Date();
	f.setItemValue('nam', f.grid._year);
	if (f._action == 'New') f.setItemValue('ky', d.getMonth() + 1);
}
function close$SalaryComputingPeriod(f) {try {f.remove_onResponseComplete(on$SalaryComputingPeriod$ResponseComplete)} catch (ex) {}}
function on$SalaryComputingPeriod$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
      break;
    default:
      break;
  }
}
